import java.io.*;
import java.util.*;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Escape special characters in userInput
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        System.out.println("Hello, " + sanitizedInput + "!");

        // Now the sanitized input can be safely displayed without introducing XSS vulnerabilities
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
